diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..5ad5007e2ed3 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -13053,7 +13053,9 @@ Instruction &BoUpSLP::getLastInstructionInBundle(const TreeEntry *E) {
                    if (E->getOpcode() == Instruction::GetElementPtr &&
                        !isa<GetElementPtrInst>(V))
                      return true;
-                   auto *I = cast<Instruction>(V);
+                   auto *I = dyn_cast<Instruction>(V);
+                   if (!I)
+                     return true;
                    return !E->isOpcodeOrAlt(I) || I->getParent() == BB ||
                           isVectorLikeInstWithConstOps(I);
                  })) &&
@@ -13077,7 +13079,8 @@ Instruction &BoUpSLP::getLastInstructionInBundle(const TreeEntry *E) {
                isVectorLikeInstWithConstOps(I)) ||
               (GatheredLoadsEntriesFirst.has_value() &&
                E->getOpcode() == Instruction::Load && E->isGather() &&
-               E->Idx < *GatheredLoadsEntriesFirst)) &&
+               E->Idx < *GatheredLoadsEntriesFirst) ||
+              (!E->isOpcodeOrAlt(I))) &&
              "Expected vector-like or non-GEP in GEP node insts only.");
       if (!DT->isReachableFromEntry(LastInst->getParent())) {
         LastInst = I;
@@ -20988,23 +20991,38 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       // the getelementptrs.
       SmallVector<Value *, 16> Bundle(Candidates.size());
       auto BundleIndex = 0u;
+      BasicBlock *CommonBB = nullptr;
+      bool AllInSameBB = true;
       for (auto *V : Candidates) {
         auto *GEP = cast<GetElementPtrInst>(V);
         auto *GEPIdx = GEP->idx_begin()->get();
         assert(GEP->getNumIndices() == 1 && !isa<Constant>(GEPIdx));
         Bundle[BundleIndex++] = GEPIdx;
+        
+        // Check if all indices are instructions in the same basic block
+        if (auto *IdxInst = dyn_cast<Instruction>(GEPIdx)) {
+          if (!CommonBB) {
+            CommonBB = IdxInst->getParent();
+          } else if (CommonBB != IdxInst->getParent()) {
+            AllInSameBB = false;
+          }
+        }
       }

-      // Try and vectorize the indices. We are currently only interested in
-      // gather-like cases of the form:
-      //
-      // ... = g[a[0] - b[0]] + g[a[1] - b[1]] + ...
-      //
-      // where the loads of "a", the loads of "b", and the subtractions can be
-      // performed in parallel. It's likely that detecting this pattern in a
-      // bottom-up phase will be simpler and less costly than building a
-      // full-blown top-down phase beginning at the consecutive loads.
-      Changed |= tryToVectorizeList(Bundle, R);
+      // Only try to vectorize if all indices are in the same basic block
+      // to avoid assertion failures in getLastInstructionInBundle
+      if (AllInSameBB) {
+        // Try and vectorize the indices. We are currently only interested in
+        // gather-like cases of the form:
+        //
+        // ... = g[a[0] - b[0]] + g[a[1] - b[1]] + ...
+        //
+        // where the loads of "a", the loads of "b", and the subtractions can be
+        // performed in parallel. It's likely that detecting this pattern in a
+        // bottom-up phase will be simpler and less costly than building a
+        // full-blown top-down phase beginning at the consecutive loads.
+        Changed |= tryToVectorizeList(Bundle, R);
+      }
     }
   }
   return Changed;

